import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  CloudDownload, Settings, ChevronLeft, Search, Loader2, 
  X, Banknote, Save, Trash2, Pencil, Plus, Download, BarChart3, QrCode, Phone, Copy, Mic, FileJson, UploadCloud,
  MessageCircle, FileSpreadsheet, ExternalLink, ChevronRight, Sparkles, Landmark, CheckCheck, Info, RefreshCcw
} from 'lucide-react';
import { exportToExcel, parseExcelFile, normalizePhoneForZalo, formatCurrency, generateVietQrUrl, normalizeString, VND_MULTIPLIER } from './utils';
import { Customer } from './types';

const parseSafe = (val: any): number => {
  if (typeof val === 'number') return val;
  if (!val) return 0;
  const clean = String(val).replace(/[^0-9.-]/g, '');
  return parseFloat(clean) || 0;
};

const calculateRow = (cust: any, rate: number) => {
  const ni = parseSafe(cust.newIndex);
  const oi = parseSafe(cust.oldIndex);
  const od = parseSafe(cust.oldDebt);
  const paid = parseSafe(cust.paid);
  const vol = (ni > 0 && ni >= oi) ? (ni - oi) : 0;
  const amt = vol * rate;
  const bal = (amt + od) - paid;
  return {
    ...cust,
    newIndex: ni, oldIndex: oi, oldDebt: od, paid: paid,
    volume: vol, amount: amt, balance: bal,
    status: bal <= 0 && ni > 0 ? 'paid' : 'unpaid'
  };
};

const App: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>(() => {
    const saved = localStorage.getItem('water_data_final_v18');
    return saved ? JSON.parse(saved) : [];
  });

  const [config, setConfig] = useState(() => {
    const saved = localStorage.getItem('water_config_v18');
    return saved ? JSON.parse(saved) : { 
      waterRate: 16.5, 
      sheetUrl1: '', 
      sheetUrl2: '', 
      bankId: 'agribank', 
      accountNo: '8888942444224', 
      accountName: 'TO TUAN KIET' 
    };
  });

  const [view, setView] = useState('list'); 
  const [activeTab, setActiveTab] = useState<'list1' | 'list2'>('list1');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showQr, setShowQr] = useState(false);
  const [onlyNonZalo, setOnlyNonZalo] = useState(false); 

  const [quickIndex, setQuickIndex] = useState('');
  const [paidInput, setPaidInput] = useState('');
  const [voiceToast, setVoiceToast] = useState<{ message: string, type: 'success' | 'error' | 'info' } | null>(null);

  const [editForm, setEditForm] = useState({ name: '', address: '', phone: '', stt: 1, oldIndex: 0, oldDebt: 0, isZalo: false });
  const [showAddModal, setShowAddModal] = useState(false);
  const [addForm, setAddForm] = useState({ name: '', address: '', phone: '', stt: 1, oldIndex: 0, oldDebt: 0, isZalo: false });

  const fileInputRef = useRef<HTMLInputElement>(null);
  const scrollTargetId = useRef<string | null>(null);

  useEffect(() => {
    localStorage.setItem('water_data_final_v18', JSON.stringify(customers));
    localStorage.setItem('water_config_v18', JSON.stringify(config));
  }, [customers, config]);

  useEffect(() => {
    if (view === 'list' && scrollTargetId.current) {
      const tid = scrollTargetId.current;
      setTimeout(() => {
        const el = document.getElementById(`cust-${tid}`);
        if (el) {
          el.scrollIntoView({ behavior: 'smooth', block: 'center' });
          el.classList.add('bg-yellow-100');
          setTimeout(() => el.classList.remove('bg-yellow-100'), 2000);
        }
        scrollTargetId.current = null;
      }, 300);
    }
  }, [view, customers]);

  const filtered = useMemo(() => {
    const s = searchQuery.toLowerCase().trim();
    return customers.filter(c => {
      const isCorrectTab = c.listType === activeTab;
      if (!isCorrectTab) return false;

      const paidVnd = String(Math.round((c.paid || 0) * VND_MULTIPLIER));
      const balanceVnd = String(Math.round((c.balance || 0) * VND_MULTIPLIER));

      const matchText = 
        String(c.name).toLowerCase().includes(s) || 
        String(c.address).toLowerCase().includes(s) || 
        String(c.phone).includes(s) || 
        String(c.stt) === s ||
        paidVnd.includes(s) ||
        balanceVnd.includes(s);

      const matchZaloFilter = onlyNonZalo ? !c.isZalo : true;
      return matchText && matchZaloFilter;
    }).sort((a, b) => a.stt - b.stt);
  }, [customers, activeTab, searchQuery, onlyNonZalo]);

  const stats = useMemo(() => {
    const list = customers.filter(c => c.listType === activeTab && !String(c.name).toUpperCase().includes("TỔNG"));
    return {
      totalCust: list.length,
      recorded: list.filter(c => (c.newIndex || 0) > (c.oldIndex || 0)).length,
      totalVol: list.reduce((sum, c) => sum + (c.volume || 0), 0),
      totalAmount: list.reduce((sum, c) => sum + (c.amount || 0), 0),
      totalOldDebt: list.reduce((sum, c) => sum + (c.oldDebt || 0), 0),
      noZalo: list.filter(c => !c.isZalo).length
    };
  }, [customers, activeTab]);

  const selectedCustomer = useMemo(() => customers.find(c => c.id === selectedId), [customers, selectedId]);

  const qrUrl = useMemo(() => {
    if (!selectedCustomer) return '';
    return generateVietQrUrl(config.bankId, config.accountNo, selectedCustomer.balance, selectedCustomer.name);
  }, [selectedCustomer, config]);

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'info') => {
    setVoiceToast({ message, type });
    setTimeout(() => setVoiceToast(null), 3000);
  };

  const handleClosingPeriod = () => {
    const msg = `Hành động này sẽ:\n1. Lấy Chỉ số mới làm Chỉ số cũ tháng sau.\n2. Chuyển Nợ còn lại sang Nợ kỳ trước tháng sau.\n3. Reset toàn bộ Số mới & Tiền thu về 0.\n\nBạn có chắc chắn muốn chốt ${activeTab === 'list1' ? 'Danh bộ 1' : 'Danh bộ 2'} không?`;
    if (!confirm(msg)) return;

    const currentTabCustomers = customers.filter(c => c.listType === activeTab);
    const otherTabCustomers = customers.filter(c => c.listType !== activeTab);

    const nextMonthCustomers = currentTabCustomers.map(c => {
      const nextOldIndex = c.newIndex > 0 ? c.newIndex : c.oldIndex;
      const nextOldDebt = c.balance;

      return calculateRow({
        ...c,
        oldIndex: nextOldIndex,
        oldDebt: nextOldDebt,
        newIndex: 0,
        paid: 0,
        isZalo: false 
      }, config.waterRate);
    });

    setCustomers([...otherTabCustomers, ...nextMonthCustomers]);
    exportToExcel(nextMonthCustomers, `Ky_Moi_${activeTab}`);

    showToast("Đã chốt kỳ & Xuất file thành công!", 'success');
    setView('list');
  };

  const handleCopyMessage = (cust: Customer, currentNewIndex: string | number) => {
    const ni = parseSafe(currentNewIndex);
    const vol = (ni > 0 && ni >= cust.oldIndex) ? (ni - cust.oldIndex) : 0;
    const amount = vol * config.waterRate;
    const total = amount + cust.oldDebt;
    const msg = `STT: ${cust.stt}\nKH: ${cust.name}\nSỐ: ${cust.oldIndex} -> ${ni} (${vol} m³)\nTIỀN: ${formatCurrency(amount)}\nNỢ CŨ: ${formatCurrency(cust.oldDebt)}\nTỔNG: ${formatCurrency(total)}\nND: TT Nuoc ${normalizeString(cust.name).toUpperCase()}`;
    navigator.clipboard.writeText(msg);
  };

  const handleAddCustomer = () => {
    const targetStt = addForm.stt || 1;
    const newCust = calculateRow({
      id: `cust-custom-${Date.now()}`,
      ...addForm,
      listType: activeTab,
      newIndex: 0,
      paid: 0
    }, config.waterRate);

    setCustomers(prev => {
      const updated = prev.map(c => {
        if (c.listType === activeTab && c.stt >= targetStt) return { ...c, stt: c.stt + 1 };
        return c;
      });
      return [...updated, newCust];
    });
    setShowAddModal(false);
    setAddForm({ name: '', address: '', phone: '', stt: targetStt + 1, oldIndex: 0, oldDebt: 0, isZalo: false });
  };

  const handleSaveEdit = () => {
    if (!selectedId) return;
    setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, ...editForm }, config.waterRate) : c));
    setView('detail');
  };

  const startVoiceAction = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) { alert("Trình duyệt không hỗ trợ."); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript.toLowerCase();
      const parts = transcript.split(/\s+số\s+/);
      if (parts.length < 2) { showToast("Sai cấu trúc giọng nói.", 'error'); return; }
      const spokenName = parts[0].trim();
      const spokenIndex = parseInt(parts[1].trim().replace(/[^0-9]/g, ''));
      const candidates = customers.filter(c => c.listType === activeTab);
      let bestMatch = candidates.find(c => normalizeString(c.name).includes(normalizeString(spokenName)));
      if (bestMatch) {
        setCustomers(prev => prev.map(c => c.id === bestMatch!.id ? calculateRow({ ...c, newIndex: spokenIndex }, config.waterRate) : c));
        scrollTargetId.current = bestMatch.id;
        showToast(`Đã ghi: ${bestMatch.name}`, 'success');
      } else showToast("Không tìm thấy khách.", 'error');
    };
    recognition.start();
  };

  const startVoiceForNewIndex = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) { alert("Trình duyệt không hỗ trợ."); return; }
    const recognition = new SpeechRecognition();
    recognition.lang = 'vi-VN';
    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      const num = transcript.replace(/[^0-9]/g, '');
      if (num) {
        setQuickIndex(num);
        showToast(`Số mới: ${num}`, 'success');
      } else {
        showToast("Không nghe rõ số.", 'error');
      }
    };
    recognition.start();
  };

  const handleSync = async () => {
    const url = activeTab === 'list1' ? config.sheetUrl1?.trim() : config.sheetUrl2?.trim();
    if (!url) { alert("Chưa nhập Link Cloud!"); return; }
    setIsSyncing(true);
    try {
      const res = await fetch(`${url}${url.includes('?') ? '&' : '?'}list=${activeTab}&t=${Date.now()}`);
      const json = await res.json();
      setCustomers(prev => {
        const other = prev.filter(c => c.listType !== activeTab);
        const mapped = json.map((item: any) => calculateRow({
          id: `cust-${item.stt}-${activeTab}`,
          stt: parseInt(item.stt), name: item.name || `(STT ${item.stt})`,
          address: item.address || "", phone: item.phone || "",
          newIndex: parseSafe(item.newIndex), oldIndex: parseSafe(item.oldIndex),
          oldDebt: parseSafe(item.oldDebt), paid: parseSafe(item.paid),
          listType: activeTab, isZalo: !!item.isZalo
        }, config.waterRate));
        return [...other, ...mapped];
      });
      alert("Xong!");
    } catch (e) { alert("Lỗi kết nối."); } finally { setIsSyncing(false); }
  };

  const handleMergeExcel = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsSyncing(true);
    try {
      const imported = await parseExcelFile(file, activeTab, config.waterRate);
      setCustomers(prev => {
        const otherTabs = prev.filter(c => c.listType !== activeTab);
        const currentTab = prev.filter(c => c.listType === activeTab);
        const mergedTab = [...currentTab];
        imported.forEach(item => {
          const idx = mergedTab.findIndex(c => c.stt === item.stt);
          if (idx !== -1) mergedTab[idx] = { ...mergedTab[idx], ...item, id: mergedTab[idx].id, listType: activeTab }; 
          else mergedTab.push({ ...item, listType: activeTab });
        });
        return [...otherTabs, ...mergedTab];
      });
      alert(`Đã gộp vào ${activeTab === 'list1' ? 'Bộ 1' : 'Bộ 2'}`);
      e.target.value = '';
    } catch (err) { alert("Lỗi file."); } finally { setIsSyncing(false); }
  };

  const openZalo = (id: string, phone: string) => {
    const cust = customers.find(c => c.id === id);
    if (cust) handleCopyMessage(cust, id === selectedId ? quickIndex : cust.newIndex);
    setCustomers(prev => prev.map(c => c.id === id ? { ...c, isZalo: true } : c));
    window.location.assign(`https://zalo.me/${normalizePhoneForZalo(phone)}`);
  };

  const navigateDetail = (direction: 'next' | 'prev') => {
    if (!selectedId) return;
    const idx = filtered.findIndex(c => c.id === selectedId);
    let target = direction === 'next' ? idx + 1 : idx - 1;
    if (target >= 0 && target < filtered.length) {
      const next = filtered[target];
      setSelectedId(next.id);
      setQuickIndex(next.newIndex > 0 ? next.newIndex.toString() : "");
      setPaidInput(next.paid > 0 ? (next.paid * VND_MULTIPLIER).toString() : ""); 
    }
  };

  useEffect(() => {
    if (view === 'detail' && selectedId) {
      const ni = parseSafe(quickIndex);
      const pi = parseSafe(paidInput) / VND_MULTIPLIER; 
      setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, newIndex: ni, paid: pi }, config.waterRate) : c));
    }
  }, [quickIndex, paidInput, view, selectedId]);

  return (
    <div className="h-screen bg-[#f3f4f6] max-w-md mx-auto flex flex-col font-sans relative overflow-hidden shadow-2xl text-slate-800">

      {voiceToast && <div className="fixed top-20 left-1/2 -translate-x-1/2 z-[200] px-6 py-3 rounded-2xl shadow-2xl font-black text-sm bg-blue-600 text-white animate-bounce">{voiceToast.message}</div>}

      {showQr && selectedCustomer && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-md z-[150] flex items-center justify-center p-6" onClick={() => setShowQr(false)}>
          <div className="bg-white rounded-[2.5rem] p-6 w-full max-w-[340px] shadow-2xl text-center flex flex-col items-center" onClick={e => e.stopPropagation()}>
            <h3 className="font-black uppercase italic text-blue-600 mb-1 text-lg">Quét Mã QR</h3>
            <p className="text-[10px] font-black text-slate-400 mb-4 uppercase truncate w-full px-4">{selectedCustomer.name}</p>
            <div className="bg-white p-2 rounded-2xl mb-4 border-2 border-slate-100 shadow-sm" style={{ width: '240px', height: '240px' }}>
               <img src={qrUrl} alt="QR" className="w-full h-full object-contain" />
            </div>
            <div className="bg-blue-50 p-4 rounded-2xl mb-6 w-full">
               <p className="text-[9px] font-black text-blue-400 uppercase mb-0.5">Số tiền thanh toán</p>
               <p className="text-2xl font-black text-blue-700">{formatCurrency(selectedCustomer.balance)}</p>
            </div>
            <button onClick={() => setShowQr(false)} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black uppercase shadow-lg">Đóng</button>
          </div>
        </div>
      )}

      {showAddModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white w-full rounded-[2rem] p-6 shadow-2xl">
            <h2 className="text-xl font-black uppercase italic mb-6">Chèn khách hàng mới</h2>
            <div className="space-y-4">
              <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Tên khách hàng" value={addForm.name} onChange={e => setAddForm({...addForm, name: e.target.value})} />
              <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Địa chỉ" value={addForm.address} onChange={e => setAddForm({...addForm, address: e.target.value})} />
              <input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" placeholder="Số điện thoại" value={addForm.phone} onChange={e => setAddForm({...addForm, phone: e.target.value})} />
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1"><label className="text-[10px] font-black uppercase">Chèn tại STT</label><input type="number" className="w-full bg-blue-50 p-4 rounded-xl border font-bold" value={addForm.stt} onChange={e => setAddForm({...addForm, stt: parseInt(e.target.value) || 1})} /></div>
                <div className="space-y-1"><label className="text-[10px] font-black uppercase">Số cũ</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={addForm.oldIndex} onChange={e => setAddForm({...addForm, oldIndex: parseFloat(e.target.value) || 0})} /></div>
              </div>
              <button onClick={handleAddCustomer} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl mt-4">Xác nhận chèn</button>
              <button onClick={() => setShowAddModal(false)} className="w-full text-slate-400 font-bold uppercase py-2">Hủy</button>
            </div>
          </div>
        </div>
      )}

      {view === 'list' && (
        <>
          <header className="p-4 flex justify-between items-center bg-white border-b shrink-0">
            <h1 className="text-xl font-black text-blue-600 italic uppercase">{activeTab === 'list1' ? 'Danh bộ 01' : 'Danh bộ 02'}</h1>
            <div className="flex gap-1">
              <button onClick={() => setShowAddModal(true)} className="p-2 text-blue-600"><Plus size={24}/></button>
              <button onClick={() => setOnlyNonZalo(!onlyNonZalo)} className={`p-2 rounded-xl ${onlyNonZalo ? 'text-blue-600 bg-blue-50' : 'text-slate-400'}`}><MessageCircle size={22}/></button>
              <button onClick={handleSync} disabled={isSyncing} className="p-2 text-blue-600">{isSyncing ? <Loader2 className="animate-spin" size={22}/> : <CloudDownload size={22}/>}</button>
              <button onClick={() => setView('config')} className="p-2 text-slate-400"><Settings size={22}/></button>
            </div>
          </header>

          <div className="p-3 shrink-0 space-y-2">
            <div className="flex gap-2">
              <div className="relative flex-1 flex items-center">
                <input className="w-full bg-white rounded-xl py-3 pl-10 pr-4 shadow-sm border outline-none text-sm font-bold" placeholder="Tìm tên, STT, Tiền..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} />
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-300" size={16} />
                <button onClick={startVoiceAction} className="ml-2 p-3 rounded-xl shadow-lg border bg-white text-blue-600 active:bg-blue-600 active:text-white transition-all"><Mic size={20} /></button>
              </div>
              <button onClick={() => setView('stats')} className="p-3 bg-white border rounded-xl shadow-sm text-blue-600"><BarChart3 size={20}/></button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto px-3 space-y-2 pb-28">
            {filtered.map(c => (
              <div key={c.id} id={`cust-${c.id}`} onClick={() => { setSelectedId(c.id); setQuickIndex(c.newIndex > 0 ? c.newIndex.toString() : ""); setPaidInput(c.paid > 0 ? (c.paid * VND_MULTIPLIER).toString() : ""); setView('detail'); }} className="bg-white p-3 rounded-2xl shadow-sm border border-slate-200 active:scale-[0.98] transition-all">
                <div className="flex items-start gap-3">
                  <div className="flex flex-col items-center gap-1 shrink-0">
                    <div className="bg-blue-600 px-2 py-1 rounded-lg min-w-[34px] text-center text-white text-[11px] font-black">{c.stt}</div>
                    <button onClick={(e) => {e.stopPropagation(); setCustomers(prev => prev.map(p => p.id === c.id ? {...p, isZalo: !p.isZalo} : p))}} className={`p-1.5 rounded-full border ${c.isZalo ? 'bg-blue-600 text-white' : 'text-slate-300'}`}><MessageCircle size={14} /></button>
                  </div>
                  <div className="flex-1 min-w-0">
                    <h3 className={`font-black uppercase text-[15px] truncate ${c.isZalo ? 'text-blue-700' : 'text-slate-900'}`}>{c.name}</h3>
                    <div className="flex items-center gap-2">
                      <p className="text-[11px] text-slate-500 font-bold truncate">{c.address || '---'}</p>
                      {c.phone && <p className="text-[10px] text-blue-600 font-black italic">{c.phone}</p>}
                    </div>
                    <div className="mt-2">
                       <button onClick={(e) => {e.stopPropagation(); openZalo(c.id, c.phone);}} className="flex items-center gap-1.5 text-[10px] font-black text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full border border-blue-200">
                          <img src="https://upload.wikimedia.org/wikipedia/commons/thumb/9/91/Icon_of_Zalo.svg/1200px-Icon_of_Zalo.svg.png" className="w-3 h-3 rounded-sm" /> ZALO / COPY
                       </button>
                    </div>
                  </div>
                  <div className="text-right shrink-0">
                    <div className="font-black text-[18px] text-rose-700 tracking-tighter">{formatCurrency(c.balance)}</div>
                    {c.newIndex > 0 ? <div className="text-[10px] font-black text-white bg-emerald-600 px-2 py-1 rounded-lg mt-1">MỚI: {c.newIndex}</div> : <div className="text-[10px] font-black text-slate-400 mt-1 uppercase">Chưa ghi</div>}
                  </div>
                </div>
              </div>
            ))}
          </div>

          <div className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-white/95 backdrop-blur-md border border-slate-200 p-1.5 rounded-2xl flex gap-1 shadow-2xl z-50">
            <button onClick={() => setActiveTab('list1')} className={`px-8 py-2.5 rounded-xl text-[11px] font-black uppercase ${activeTab === 'list1' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}>Bộ 01</button>
            <button onClick={() => setActiveTab('list2')} className={`px-8 py-2.5 rounded-xl text-[11px] font-black uppercase ${activeTab === 'list2' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}>Bộ 02</button>
          </div>
        </>
      )}

      {view === 'detail' && selectedCustomer && (
        <div className="h-full bg-white flex flex-col p-4 animate-in slide-in-from-right duration-200">
          <header className="flex justify-between items-center mb-6">
            <div className="flex items-center gap-1">
              <button onClick={() => setView('list')} className="p-2 text-slate-400"><ChevronLeft size={36}/></button>
              <div className="flex bg-slate-50 rounded-xl p-1 border">
                <button onClick={() => navigateDetail('prev')} className="p-2 text-slate-400"><ChevronLeft size={20}/></button>
                <button onClick={() => navigateDetail('next')} className="p-2 text-slate-400"><ChevronRight size={20}/></button>
              </div>
            </div>
            <div className="flex gap-2">
              <button onClick={() => { setEditForm({ name: selectedCustomer.name, address: selectedCustomer.address, phone: selectedCustomer.phone, stt: selectedCustomer.stt, oldIndex: selectedCustomer.oldIndex, oldDebt: selectedCustomer.oldDebt, isZalo: !!selectedCustomer.isZalo }); setView('edit_customer'); }} className="p-3 bg-slate-50 rounded-full border"><Pencil size={20}/></button>
              <button onClick={() => { handleCopyMessage(selectedCustomer, quickIndex); alert("Đã copy!"); }} className="p-3 bg-blue-50 text-blue-600 rounded-full border"><Copy size={20}/></button>
              <button onClick={() => setShowQr(true)} className="p-3.5 bg-blue-600 text-white rounded-full shadow-xl"><QrCode size={22}/></button>
            </div>
          </header>

          <div className="flex-1 space-y-4 overflow-y-auto px-2">
            <div className="border-l-4 border-blue-600 pl-4">
              <span className="bg-blue-600 text-white text-[10px] font-black px-2 py-0.5 rounded">STT: {selectedCustomer.stt}</span>
              <h2 className="font-black uppercase text-xl text-slate-900 leading-tight">{selectedCustomer.name}</h2>
              <p className="text-sm text-slate-500 italic">{selectedCustomer.address}</p>
            </div>

            <div className="bg-slate-50 rounded-3xl p-5 border shadow-inner text-center">
              <div className="grid grid-cols-2 gap-4">
                <div><p className="text-[10px] font-black text-slate-400 uppercase">Số cũ</p><div className="text-4xl font-black">{selectedCustomer.oldIndex}</div></div>
                <div>
                  <p className="text-[10px] font-black text-blue-600 uppercase">Số mới</p>
                  <div className="flex items-center justify-center relative">
                    <input autoFocus type="number" className="w-full text-center text-4xl font-black text-blue-600 bg-transparent outline-none ml-6" value={quickIndex} onChange={e => setQuickIndex(e.target.value)} />
                    <button onClick={startVoiceForNewIndex} className="p-2 text-blue-400 active:text-blue-600"><Mic size={22} /></button>
                  </div>
                </div>
              </div>
            </div>

            <div className="space-y-3 bg-white border p-5 rounded-3xl shadow-sm">
              <div className="flex justify-between font-bold text-slate-500"><span>Tiêu thụ:</span><span>{selectedCustomer.volume} m³</span></div>
              <div className="flex justify-between font-bold text-slate-500"><span>Tiền Nước:</span><span>{formatCurrency(selectedCustomer.amount)}</span></div>
              <div className="flex justify-between font-bold text-rose-500"><span>Nợ cũ:</span><span>{formatCurrency(selectedCustomer.oldDebt)}</span></div>
              <div className="border-t pt-3 flex justify-between items-center font-black text-blue-600 text-xl"><span>TỔNG CỘNG:</span><span className="text-3xl">{formatCurrency(selectedCustomer.balance)}</span></div>
            </div>

            <div className="grid grid-cols-10 gap-3 mt-4">
              <div className="col-span-6 bg-emerald-50 rounded-2xl p-4 border border-emerald-100 text-center flex flex-col justify-center relative group">
                <p className="text-[9px] font-black text-emerald-600 uppercase mb-1">Khách trả (VNĐ)</p>
                <div className="relative flex items-center">
                  <input type="number" className="w-full text-center text-3xl font-black text-emerald-600 bg-transparent outline-none pr-8" value={paidInput} placeholder="0" onChange={e => setPaidInput(e.target.value)} />
                  {paidInput && (
                    <button onClick={() => setPaidInput('')} className="absolute right-0 text-emerald-400 hover:text-emerald-600 p-1">
                      <X size={20} />
                    </button>
                  )}
                </div>
              </div>
              <div className="col-span-4 flex flex-col gap-2">
                <button onClick={() => { 
                    const totalVnd = Math.round(selectedCustomer.balance * VND_MULTIPLIER);
                    setPaidInput(totalVnd.toString()); 
                    setCustomers(prev => prev.map(c => c.id === selectedId ? calculateRow({ ...c, newIndex: parseSafe(quickIndex), paid: selectedCustomer.balance }, config.waterRate) : c)); 
                }} className="flex-1 bg-emerald-600 text-white rounded-2xl font-black uppercase text-[11px] shadow-md active:scale-95">Thu đủ</button>
                <button onClick={() => { scrollTargetId.current = selectedId; setView('list'); }} className="flex-1 bg-blue-600 text-white rounded-2xl font-black uppercase text-[11px] shadow-md active:scale-95">Lưu & Về</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {view === 'edit_customer' && selectedCustomer && (
        <div className="h-full bg-white p-6 animate-in slide-in-from-bottom duration-200">
          <header className="flex justify-between items-center mb-6"><h2 className="text-xl font-black uppercase italic text-slate-800">Sửa thông tin</h2><button onClick={() => setView('detail')} className="p-2 bg-slate-100 rounded-full"><X size={20}/></button></header>
          <div className="space-y-4 pb-10">
            <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Họ tên</label><input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.name || ''} onChange={e => setEditForm({...editForm, name: e.target.value})} /></div>
            <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Địa chỉ</label><input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.address || ''} onChange={e => setEditForm({...editForm, address: e.target.value})} /></div>
            <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Số điện thoại</label><input className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.phone || ''} onChange={e => setEditForm({...editForm, phone: e.target.value})} /></div>
            <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Nợ cũ</label><input type="number" className="w-full bg-slate-50 p-4 rounded-xl border font-bold" value={editForm.oldDebt || 0} onChange={e => setEditForm({...editForm, oldDebt: parseFloat(e.target.value) || 0})} /></div>
            <div className="flex gap-3 mt-6">
              <button onClick={() => { if(confirm("Xóa khách?")) { setCustomers(prev => prev.filter(c => c.id !== selectedId)); setView('list'); } }} className="bg-rose-50 text-rose-600 p-4 rounded-2xl border border-rose-100"><Trash2 size={24}/></button>
              <button onClick={handleSaveEdit} className="flex-1 bg-blue-600 text-white py-4 rounded-2xl font-black uppercase shadow-xl">Lưu Thay Đổi</button>
            </div>
          </div>
        </div>
      )}

      {view === 'config' && (
        <div className="h-full bg-white p-6 overflow-y-auto">
          <header className="flex justify-between items-center mb-6 shrink-0"><h2 className="text-xl font-black uppercase italic text-slate-800">Cấu hình</h2><button onClick={() => setView('list')} className="p-2 bg-slate-100 rounded-full"><X size={20}/></button></header>
          <div className="space-y-5 pb-20">
            <div className="bg-slate-50 border-2 border-dashed border-slate-200 p-6 rounded-3xl space-y-4 text-center">
              <div className="flex flex-col items-center gap-1 mb-2">
                <p className="text-[10px] font-black text-slate-400 uppercase">Danh bộ Excel hiện tại</p>
                <div className="bg-blue-600 text-white px-4 py-1.5 rounded-full font-black text-xs uppercase">{activeTab === 'list1' ? 'DANH BỘ 01' : 'DANH BỘ 02'}</div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <button onClick={() => fileInputRef.current?.click()} className="bg-emerald-600 text-white p-4 rounded-2xl shadow-lg font-black uppercase flex flex-col items-center gap-2"><UploadCloud size={24}/> Gộp File</button>
                <button onClick={() => exportToExcel(customers.filter(c => c.listType === activeTab), `Backup_${activeTab}`)} className="bg-white border-2 border-slate-200 text-slate-600 p-4 rounded-2xl font-black uppercase flex flex-col items-center gap-2"><FileSpreadsheet size={24}/> Sao lưu</button>
              </div>
              <input type="file" ref={fileInputRef} className="hidden" accept=".xlsx,.xls" onChange={handleMergeExcel} />
            </div>

            <div className="space-y-4">
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Đơn giá nước (Logic: 16.5 = 16.500đ)</label><input className="w-full bg-slate-100 p-4 rounded-xl text-2xl font-black text-blue-600 outline-none" type="number" step="0.1" value={config.waterRate} onChange={e => setConfig({...config, waterRate: parseSafe(e.target.value)})} /></div>
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Mã Ngân hàng (vba, vcb, mb...)</label><input className="w-full bg-white p-4 border rounded-xl font-black" placeholder="vba" value={config.bankId} onChange={e => setConfig({...config, bankId: e.target.value})} /></div>
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Số tài khoản</label><input className="w-full bg-white p-4 border rounded-xl font-black" placeholder="8888942444224" value={config.accountNo} onChange={e => setConfig({...config, accountNo: e.target.value})} /></div>
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Tên chủ tài khoản</label><input className="w-full bg-white p-4 border rounded-xl font-black uppercase" placeholder="TÊN CHỦ TÀI KHOẢN" value={config.accountName} onChange={e => setConfig({...config, accountName: e.target.value.toUpperCase()})} /></div>

               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Link Cloud Bộ 1 (Script App)</label><input className="w-full bg-slate-50 p-4 border rounded-xl text-xs" placeholder="https://script.google.com/..." value={config.sheetUrl1} onChange={e => setConfig({...config, sheetUrl1: e.target.value})} /></div>
               <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500">Link Cloud Bộ 2 (Script App)</label><input className="w-full bg-slate-50 p-4 border rounded-xl text-xs" placeholder="https://script.google.com/..." value={config.sheetUrl2} onChange={e => setConfig({...config, sheetUrl2: e.target.value})} /></div>
            </div>

            <button onClick={() => setView('list')} className="w-full bg-blue-600 text-white py-5 rounded-2xl font-black uppercase shadow-2xl active:scale-95">Lưu & Đóng</button>
            <button onClick={() => { if(confirm("Xóa dữ liệu App?")) { localStorage.clear(); location.reload(); } }} className="w-full text-rose-500 font-black text-[10px] uppercase flex items-center justify-center gap-1 mt-10"><Trash2 size={12}/> Xóa dữ liệu app</button>
          </div>
        </div>
      )}

      {view === 'stats' && (
        <div className="h-full bg-white flex flex-col p-3 animate-in slide-in-from-bottom duration-200">
          <header className="flex items-center gap-3 mb-2 shrink-0">
            <button onClick={() => setView('list')} className="p-2 bg-slate-50 rounded-full"><ChevronLeft size={24}/></button>
            <h1 className="text-lg font-black uppercase italic text-slate-800">Thống kê</h1>
          </header>

          <div className="grid grid-cols-2 gap-2 mb-2 shrink-0">
            <div className="bg-blue-50 p-3 rounded-2xl text-center font-black text-blue-600 shadow-sm border border-blue-100">
              <p className="text-[9px] uppercase mb-0.5 opacity-60">Tổng số</p>
              <p className="text-xl">{stats.totalCust}</p>
            </div>
            <div className="bg-emerald-50 p-3 rounded-2xl text-center font-black text-emerald-600 shadow-sm border border-emerald-100">
              <p className="text-[9px] uppercase mb-0.5 opacity-60">Đã ghi</p>
              <p className="text-xl">{stats.recorded}</p>
            </div>
          </div>

          <div className="bg-white border p-4 space-y-3 shadow-sm rounded-3xl flex-1 overflow-y-auto border-slate-100 mb-2">
             <div className="flex justify-between font-bold text-slate-600 text-xs"><span>Tiêu thụ:</span><span>{stats.totalVol || 0} m³</span></div>
             <div className="flex justify-between font-black text-blue-600 text-xs"><span>Tiền nước:</span><span>{formatCurrency(stats.totalAmount || 0)}</span></div>
             <div className="flex justify-between font-bold text-rose-600 text-xs"><span>Nợ cũ:</span><span>{formatCurrency(stats.totalOldDebt || 0)}</span></div>
             <div className="border-t pt-2 mt-2 flex justify-between font-black text-base italic uppercase text-slate-900">
               <span>TỔNG THU:</span>
               <span>{formatCurrency((stats.totalAmount || 0) + (stats.totalOldDebt || 0))}</span>
             </div>
          </div>

          <div className="space-y-2 shrink-0 pb-12">
            <button 
              onClick={handleClosingPeriod} 
              className="w-full bg-amber-500 text-white py-3.5 rounded-2xl font-black uppercase shadow-md flex justify-center items-center gap-2 active:scale-95 transition-all text-sm"
            >
              <RefreshCcw size={18}/> Chốt kỳ & Mở tháng mới
            </button>
            <button 
              onClick={() => exportToExcel(customers.filter(c => c.listType === activeTab), `BaoCao_${activeTab}`)} 
              className="w-full bg-blue-600 text-white py-3.5 rounded-2xl font-black uppercase shadow-md flex justify-center items-center gap-2 active:scale-95 text-sm"
            >
              <Download size={18}/> Xuất báo cáo Excel
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
